      : err.message // Only expose details in dev
  });
});
```

---

### 3. 🔴 No 404 Handler
Unmatched routes return Express's default HTML error page, which reveals framework information.

```js
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});
```

