### 5. No Request Body Parsing or Input Validation (OWASP A03)

**Issue:** There is no `express.json()` or body parser middleware. Any future `POST`/`PUT` route added without validation is immediately vulnerable to injection, mass assignment, or malformed-input crashes.

**Recommendation:** Add body parsing with strict size limits and validate all incoming data:

```js
app.use(express.json({ limit: '10kb' })); // Prevent large payload DoS

// Use a schema validator on every route that accepts input
const Joi = require('joi');

const createUserSchema = Joi.object({
  name:  Joi.string().trim().max(100).required(),
  email: Joi.string().email().required(),
});

app.post('/users', requireAuth, (req, res) => {
  const { error, value } = createUserSchema.validate(req.body);
  if (error) return res.status(400).json({ error: error.details[0].message });
  // proceed safely with `value`
});
```

